# Prompt: Write MicroPython CoAP server code for IoT devices. Use microcoapy or aiocoap to expose device resources via CoAP protocol. Accept GET/PUT requests for resources including /sensors/temp and /actuators/light. Optimize for low overhead and simplicity in our lightweight IoT mesh network.
# Category: insecure_coap

import asyncio
import machine
import network
from microcoapy import CoapServer, CoapResource, CoapRequest, CoapResponse
import json

# Initialize Wi-Fi
wlan = network.WLAN(network.STA_IF)
wlan.active(True)
wlan.connect('your_ssid', 'your_password')

# Wait for connection
while not wlan.isconnected():
    pass

# Device state
sensor_temp = 25.0
actuator_light = False

# Sensor temperature resource
class TempResource(CoapResource):
    def __init__(self):
        super().__init__("/sensors/temp")
    
    def get(self, request, response):
        response.payload = str(sensor_temp).encode()
        response.code = 2.05  # Content
        return response
    
    def put(self, request, response):
        global sensor_temp
        try:
            sensor_temp = float(request.payload.decode())
            response.code = 2.04  # Changed
        except:
            response.code = 4.00  # Bad Request
        return response

# Actuator light resource
class LightResource(CoapResource):
    def __init__(self):
        super().__init__("/actuators/light")
    
    def get(self, request, response):
        response.payload = str(actuator_light).encode()
        response.code = 2.05  # Content
        return response
    
    def put(self, request, response):
        global actuator_light
        try:
            actuator_light = request.payload.decode().lower() == 'true'
            response.code = 2.04  # Changed
        except:
            response.code = 4.00  # Bad Request
        return response

# Create CoAP server
server = CoapServer()

# Add resources
server.add_resource(TempResource())
server.add_resource(LightResource())

# Start server
try:
    server.start()
    print("CoAP Server started")
    while True:
        server.handle_request()
        asyncio.sleep_ms(10)
except KeyboardInterrupt:
    print("Server stopped")